export type PriceHistoryInterval = '1m' | '5m' | '15m' | '1h' | '4h' | '1d' | '1w';
export interface PricePoint {
    timestamp: bigint;
    price: bigint;
    volume: bigint;
    option: number;
}
export interface PriceCandle {
    timestamp: bigint;
    open: bigint;
    high: bigint;
    low: bigint;
    close: bigint;
    volume: bigint;
    trades: number;
}
export interface PriceHistoryResult {
    marketId: string;
    marketAddress: `0x${string}`;
    optionIndex: number;
    interval: PriceHistoryInterval;
    candles: PriceCandle[];
}
export interface GetPriceHistoryParams {
    marketId: string;
    optionIndex: number;
    interval: PriceHistoryInterval;
    from?: bigint;
    to?: bigint;
    limit?: number;
    subgraphUrl: string;
    subgraphApiKey?: string;
    apiUrl: string;
}
